+            BufferedReader in = new BufferedReader
+                    (new InputStreamReader(getIn()));
+            String prompt = getPrompt(se);
+            se.put(ScriptEngine.FILENAME, "<STDIN>");
+            while (true) {
+                getError().print(prompt);
+                String source = "";
