+                    source = in.readLine();
+                } catch (IOException ioe) {
+                    getError().println(ioe.toString());
+                }
+                if (source == null || "quit".equals(source)) {
+                    break;
+                }
+                Object res = evaluateString(se, source, false);
+                if (res != V8Undefined.INSTANCE) {
+                    try {
+                        res = res == null ? "null" : res.toString();
+                        getError().println(res);
+                    } catch (Exception exp) {
+                        getError().println(exp.getMessage());
+                    }
+                }
+            }
