+// Destructor for jvmv8 isolate data
+JVMV8IsolateData::~JVMV8IsolateData() {
+    TRACE("JVMV8IsolateData::~JVMV8IsolateData");
+    this->globalTemplate.Reset();
+    this->jsObjectTemplate.Reset();
