+// Wrap Java object to appropriate V8 script object (when passed from java code).
+// Throws Java Exception on failure.
+Local<Value> j2v_java_wrap(V8Scope& scope, jobject object) {
+    TRACE("j2v_java_wrap");
+    return j2v_java_wrap(scope, object, true);
+}
