+        // create a java ByteBuffer and populate values
+        ByteBuffer bb = ByteBuffer.allocateDirect(12);
+        bb.order(ByteOrder.nativeOrder());
+        IntBuffer ib = bb.asIntBuffer();
+        ib.put(1);
+        ib.put(12);
+        ib.put(123);
